import{_ as a,o as l,c as o,a2 as e}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"福海景区","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/fuhai.md","filePath":"landmarks/yuanmingyuan/fuhai.md","lastUpdated":1784720050000}'),r={name:"landmarks/yuanmingyuan/fuhai.md"};function n(i,t,s,u,h,g){return l(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="福海景区" tabindex="-1">福海景区 <a class="header-anchor" href="#福海景区" aria-label="Permalink to &quot;福海景区&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1655967392727-e8f6c7c61064?w=1200&amp;q=80" alt="福海"></p><blockquote><p>三山在望，一碧万顷。福海之上，曾有龙舟竞渡、蓬岛仙山——圆明园不只有废墟的苍凉，也有湖光的温柔。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>福海是圆明园中<strong>最大的湖面</strong>，位于圆明园（主园）东部，东西宽约500米，南北长约600米，水面开阔，烟波浩渺。其名取&quot;福如东海&quot;之意，是清代帝王在园中泛舟、宴游、观龙舟的主要水域。</p><p>福海一带原是圆明园四十景中景色最集中的区域之一，环湖曾散布&quot;蓬岛瑶台&quot;&quot;湖山在望&quot;&quot;一碧万顷&quot;&quot;接秀山房&quot;&quot;别有洞天&quot;等十余处景点，亭台楼阁掩映于柳岸荷风之间。1860年10月焚劫之后，环湖建筑尽毁，如今唯余山形水系与遗址基址，幸而湖水依旧、草木复荣。</p><p>今天的福海是圆明园自然气息最浓的区域：<strong>夏日荷花满湖</strong>，接天莲叶；<strong>秋日银杏金黄</strong>，芦荻瑟瑟。从西洋楼的石砾废墟走到福海边，历史的沉重与自然的生机在此交汇，令人感慨万千。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>水域规模</strong></td><td style="text-align:left;">东西宽约500米，南北长约600米，圆明园最大湖面</td></tr><tr><td style="text-align:left;"><strong>核心景观</strong></td><td style="text-align:left;">蓬岛瑶台（湖中三岛）</td></tr><tr><td style="text-align:left;"><strong>历史功能</strong></td><td style="text-align:left;">泛舟宴游、端午龙舟竞渡、避暑理政</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">含在大门10元门票内；游船另收费</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">夏季赏荷（6-8月）、秋季观银杏（10月下旬-11月）</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="蓬岛瑶台" tabindex="-1">蓬岛瑶台 <a class="header-anchor" href="#蓬岛瑶台" aria-label="Permalink to &quot;蓬岛瑶台&quot;">​</a></h3><p>福海中央有<strong>东、北、西三座小岛</strong>，象征中国古典仙境中的<strong>蓬莱、方丈、瀛洲</strong>三座神山，合称&quot;蓬岛瑶台&quot;。此景仿唐代画家<strong>李思训</strong>的金碧山水画意营造：岛上殿阁以金碧彩画装饰，云雾缭绕时宛如海上仙山。</p><p>雍正、乾隆均极爱此景，乾隆曾赋诗数十首咏之。如今三岛尚存，中岛可乘船登临，岛上复建有部分殿宇，是福海游览的精华所在。</p><h3 id="环湖诸景" tabindex="-1">环湖诸景 <a class="header-anchor" href="#环湖诸景" aria-label="Permalink to &quot;环湖诸景&quot;">​</a></h3><p>福海周边曾环列多处名景，均为圆明园&quot;四十景&quot;或续增景观：</p><ul><li><strong>湖山在望</strong>：位于福海西北，登临可尽揽全湖山光水色</li><li><strong>一碧万顷</strong>：福海西岸敞轩，取范仲淹《岳阳楼记》&quot;一碧万顷&quot;之意，观湖最佳处</li><li><strong>接秀山房</strong>：东南岸观西山落日之所，&quot;西山暮霭&quot;尽收眼底</li><li><strong>别有洞天</strong>：福海东南隅幽僻小园，自成天地</li><li><strong>望瀛洲</strong>：西岸观龙舟的御座所在</li></ul><p>如今诸景虽已不存，遗址上设有标识说明，沿湖步道仍可环湖一周（约5公里）。</p><h3 id="龙舟竞渡场" tabindex="-1">龙舟竞渡场 <a class="header-anchor" href="#龙舟竞渡场" aria-label="Permalink to &quot;龙舟竞渡场&quot;">​</a></h3><p>福海西岸&quot;望瀛洲&quot;一带水面，是清代皇家端午龙舟竞渡的固定场所。每年五月初五前后，皇帝奉皇太后临幸福海：</p><ul><li>八旗各遣龙舟竞渡，鼓声震天</li><li>御座设于望瀛洲亭，太后、后妃于帘后观赛</li><li>赛后赐宴群臣，颁赏彩缎，是圆明园最热闹的节令盛事</li></ul><p>这一传统自雍正朝延续至咸丰初年，前后百余年，堪称清代宫廷的&quot;水上运动会&quot;。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="雍正的-仙境-执念" tabindex="-1">雍正的&quot;仙境&quot;执念 <a class="header-anchor" href="#雍正的-仙境-执念" aria-label="Permalink to &quot;雍正的&quot;仙境&quot;执念&quot;">​</a></h3><p>蓬岛瑶台的营造，源于帝王对长生仙境的向往。传说秦始皇、汉武帝皆曾遣人入海求仙，而圆明园将&quot;三神山&quot;直接搬入园中湖上——皇帝无需出海，即可&quot;置身仙境&quot;。</p><p>雍正帝常于夏日避暑福海，在蓬岛瑶台处理政务，这里实际上是圆明园的&quot;水上政务中心&quot;。园居理政的传统自此延续，圆明园在清代政治中的地位日益超越紫禁城。</p><h3 id="咸丰朝最后的龙舟" tabindex="-1">咸丰朝最后的龙舟 <a class="header-anchor" href="#咸丰朝最后的龙舟" aria-label="Permalink to &quot;咸丰朝最后的龙舟&quot;">​</a></h3><p>咸丰初年，福海龙舟竞渡仍年年举行。1860年春，内忧外患已深，咸丰帝仍于福海观龙舟——这是圆明园最后一次端午盛典。</p><p>当年十月，英法联军入园，福海环湖建筑尽付一炬。据载大火自福海一带燃起，蓬岛瑶台的殿阁在火光中映红整片湖面，成为这座名园最后的画面。此后百余年，福海只余空阔水面，直到1980年代整修水系，重植荷柳，湖光方才重现。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>蓬岛瑶台三岛</strong>：福海精华，可乘船登中岛，回望全湖（游船约20-40元/人）</li><li><strong>福海环湖步道</strong>：全程约5公里，柳岸荷风，是园内最佳徒步路线</li><li><strong>夏日荷花</strong>：6-8月湖面荷花盛开，为北京最佳赏荷地之一</li><li><strong>秋日银杏大道</strong>：10月下旬至11月初，福海西岸银杏金黄如毯</li><li><strong>龙舟竞渡遗址标识</strong>：西岸设有说明牌，讲述百年端午盛典</li><li><strong>西山借景</strong>：晴朗之日西望，玉泉山塔影与湖光相映，体会古人&quot;借景&quot;之妙</li><li><strong>遗址基址标识</strong>：环湖设有&quot;四十景&quot;各景点的方位标识，是读懂圆明园格局的露天课堂</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>福海区域开阔，步行环湖约需1.5-2小时；时间紧可只走西岸精华段（约40分钟）</li><li><strong>游船</strong>：福海码头提供电瓶船与脚踏船，登蓬岛瑶台建议乘船</li><li>湖区无遮阴处较多，夏季注意防晒，携带饮水</li><li>建议与<a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼遗址</a>组合游览：先遗址后福海，情绪由沉重转舒缓</li><li>荷花季（6-8月）清晨开园即入，光线柔和且游客稀少</li><li>环湖步道平坦，适合推婴儿车与轮椅出行；冬季湖面结冰，偶有冰嬉活动</li><li>摄影推荐：黄昏时分的蓬岛瑶台剪影、秋日西岸银杏大道</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/qichun-yuan.html">绮春园</a>——南门入口与另一处赏荷佳地</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>——长春园北部遗址核心区</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——1860年焚毁始末</li></ul><hr><p><strong>📍 位置</strong>：圆明园（主园）东部，三园交界以西 <strong>⏱️ 建议游览</strong>：1-2小时（环湖），登岛另加30分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',36)])])}const p=a(r,[["render",n]]);export{q as __pageData,p as default};
